#include <stdio.h>
#include <stdlib.h>

int cmp_desc(const void *a, const void *b) {
    long long x = *(const long long *)a;
    long long y = *(const long long *)b;
    return (x < y) - (x > y); // descending order
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, M;
        long long H;
        scanf("%d %d %lld", &N, &M, &H);
        long long *cars = (long long *)malloc(N * sizeof(long long));
        long long *outlets = (long long *)malloc(M * sizeof(long long));
        for (int i = 0; i < N; ++i) scanf("%lld", &cars[i]);
        for (int i = 0; i < M; ++i) scanf("%lld", &outlets[i]);
        qsort(cars, N, sizeof(long long), cmp_desc);
        qsort(outlets, M, sizeof(long long), cmp_desc);
        int k = N < M ? N : M;
        long long ans = 0;
        for (int i = 0; i < k; ++i) {
            long long possible = outlets[i] * H;
            ans += (possible <= cars[i]) ? possible : cars[i];
        }
        printf("%lld\n", ans);
        free(cars);
        free(outlets);
    }
    return 0;
}

